     2→pragma solidity ^0.8.24;
     3→
     4→import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
     5→import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
     6→import {Math} from "@openzeppelin/contracts/utils/math/Math.sol";
     7→import {IAggregatorV3} from "./interfaces/IAggregatorV3.sol";
     8→
     9→/// @title YieldVault
    10→/// @notice Per-user vault that holds wstETH on Base. The owner (human) deposits principal,
    11→///         and an agent wallet can withdraw a configurable share of accrued yield on a cooldown.
    12→///         Yield is computed via the Chainlink wstETH/stETH exchange rate oracle.
    13→///         Deployed as an EIP-1167 clone by YieldVaultFactory.
    14→contract YieldVault {
    15→    using SafeERC20 for IERC20;
    16→    using Math for uint256;
    17→
    18→    // ──────────────────────────────────────────────
    19→    //  Constants
    20→    // ──────────────────────────────────────────────
    21→
    22→    address public constant WSTETH = 0xc1CBa3fCea344f92D9239c08C0568f6F2F0ee452;
    23→    address public constant ORACLE = 0xB88BAc61a4Ca37C43a3725912B1f472c9A5bc061;
    24→    uint256 public constant ORACLE_STALENESS = 90_000; // 25 hours
    25→    uint256 public constant BPS_DENOMINATOR = 10_000;
    26→
    27→    // ──────────────────────────────────────────────
    28→    //  State
    29→    // ──────────────────────────────────────────────
    30→
    31→    address public factory;
    32→    address public owner;
    33→
    34→    /// @notice The depositor's principal denominated in stETH (18 decimals).
    35→    ///         Yield = totalValueInStETH - principalStETH.
    36→    uint256 public principalStETH;
    37→
    38→    // Agent configuration
    39→    address public agentWallet;
    40→    uint16 public yieldShareBps;
    41→    uint32 public withdrawalFrequency;
    42→    uint32 public lastAgentWithdrawal;
    43→
    44→    // Safety
    45→    bool public paused;
    46→    bool public initialized;
    47→
    48→    // Reentrancy lock (0 = unlocked, 1 = locked). Works in clones (storage starts at 0).
    49→    uint256 private _locked;
    50→
    51→    // ──────────────────────────────────────────────
    52→    //  Events
    53→    // ──────────────────────────────────────────────
    54→
    55→    event Deposited(uint256 wstETHAmount, uint256 newPrincipalStETH);
    56→    event PrincipalWithdrawn(address indexed to, uint256 wstETHAmount);
    57→    event YieldWithdrawn(address indexed to, uint256 wstETHAmount);
    58→    event AgentWithdrawal(address indexed agent, uint256 wstETHAmount);
    59→    event SettingsUpdated(address agent, uint16 yieldShareBps, uint32 frequency);
    60→    event VaultPaused();
    61→    event VaultUnpaused();
    62→
    63→    // ──────────────────────────────────────────────
    64→    //  Errors
    65→    // ──────────────────────────────────────────────
    66→
    67→    error AlreadyInitialized();
    68→    error NotOwner();
    69→    error NotAgent();
    70→    error Reentrancy();
    71→    error VaultIsPaused();
    72→    error ZeroAmount();
    73→    error ZeroAddress();
    74→    error ExceedsPrincipal();
    75→    error ExceedsYield();
    76→    error ExceedsBudget();
    77→    error CooldownNotElapsed();
    78→    error StaleOracle();
    79→    error InvalidOracleAnswer();
    80→    error InvalidYieldShare();
    81→    error NothingToWithdraw();
    82→
    83→    // ──────────────────────────────────────────────
    84→    //  Modifiers
    85→    // ──────────────────────────────────────────────
    86→
    87→    modifier onlyOwner() {
    88→        if (msg.sender != owner) revert NotOwner();
    89→        _;
    90→    }
    91→
    92→    modifier whenNotPaused() {
    93→        if (paused) revert VaultIsPaused();
    94→        if (IYieldVaultFactory(factory).paused()) revert VaultIsPaused();
    95→        _;
    96→    }
    97→
    98→    modifier nonReentrant() {
    99→        if (_locked == 1) revert Reentrancy();
   100→        _locked = 1;
   101→        _;
   102→        _locked = 0;
   103→    }
   104→
   105→    // ──────────────────────────────────────────────
   106→    //  Initialization (called once by factory)
   107→    // ──────────────────────────────────────────────
   108→
   109→    function initialize(
   110→        address _factory,
   111→        address _owner,
   112→        address _agent,
   113→        uint16 _yieldShareBps,
   114→        uint32 _frequency
   115→    ) external {
   116→        if (initialized) revert AlreadyInitialized();
   117→        if (_owner == address(0)) revert ZeroAddress();
   118→        if (_agent == address(0)) revert ZeroAddress();
   119→        if (_yieldShareBps > BPS_DENOMINATOR) revert InvalidYieldShare();
   120→
   121→        initialized = true;
   122→        factory = _factory;
   123→        owner = _owner;
   124→        agentWallet = _agent;
   125→        yieldShareBps = _yieldShareBps;
   126→        withdrawalFrequency = _frequency;
   127→    }
   128→
   129→    // ──────────────────────────────────────────────
   130→    //  Owner (human) functions
   131→    // ──────────────────────────────────────────────
   132→
   133→    /// @notice Deposit wstETH into the vault. Caller must have approved this contract.
   134→    function deposit(uint256 wstETHAmount) external onlyOwner whenNotPaused nonReentrant {
   135→        if (wstETHAmount == 0) revert ZeroAmount();
   136→
   137→        uint256 currentRate = _getCurrentRate();
   138→        principalStETH += wstETHAmount.mulDiv(currentRate, 1e18);
   139→
   140→        IERC20(WSTETH).safeTransferFrom(msg.sender, address(this), wstETHAmount);
   141→
   142→        emit Deposited(wstETHAmount, principalStETH);
   143→    }
   144→
   145→    /// @notice Withdraw wstETH that belongs to principal (does not touch yield).
   146→    function withdrawPrincipal(uint256 wstETHAmount) external onlyOwner whenNotPaused nonReentrant {
   147→        if (wstETHAmount == 0) revert ZeroAmount();
   148→
   149→        uint256 currentRate = _getCurrentRate();
   150→        uint256 principalInWstETH = principalStETH.mulDiv(1e18, currentRate);
   151→        if (wstETHAmount > principalInWstETH) revert ExceedsPrincipal();
   152→
   153→        principalStETH -= wstETHAmount.mulDiv(currentRate, 1e18);
   154→
   155→        IERC20(WSTETH).safeTransfer(owner, wstETHAmount);
   156→
   157→        emit PrincipalWithdrawn(owner, wstETHAmount);
   158→    }
   159→
   160→    /// @notice Withdraw accrued yield (owner has full access to yield).
   161→    function withdrawYield(uint256 wstETHAmount) external onlyOwner whenNotPaused nonReentrant {
   162→        if (wstETHAmount == 0) revert ZeroAmount();
   163→
   164→        uint256 yieldWstETH = getAccruedYieldInWstETH();
   165→        if (wstETHAmount > yieldWstETH) revert ExceedsYield();
   166→
   167→        // principalStETH unchanged — only yield leaves
   168→        IERC20(WSTETH).safeTransfer(owner, wstETHAmount);
   169→
   170→        emit YieldWithdrawn(owner, wstETHAmount);
   171→    }
   172→
   173→    /// @notice Emergency exit: withdraw everything. Works even when paused.
   174→    function exit() external onlyOwner nonReentrant {
   175→        uint256 balance = IERC20(WSTETH).balanceOf(address(this));
   176→        if (balance == 0) revert NothingToWithdraw();
   177→
   178→        principalStETH = 0;
   179→
   180→        IERC20(WSTETH).safeTransfer(owner, balance);
   181→
   182→        emit PrincipalWithdrawn(owner, balance);
   183→    }
   184→
   185→    /// @notice Update agent wallet, yield share, and withdrawal frequency.
   186→    function updateSettings(address _agent, uint16 _yieldShareBps, uint32 _frequency) external onlyOwner {
   187→        if (_agent == address(0)) revert ZeroAddress();
   188→        if (_yieldShareBps > BPS_DENOMINATOR) revert InvalidYieldShare();
   189→
   190→        agentWallet = _agent;
   191→        yieldShareBps = _yieldShareBps;
   192→        withdrawalFrequency = _frequency;
   193→
   194→        emit SettingsUpdated(_agent, _yieldShareBps, _frequency);
   195→    }
   196→
   197→    function pause() external onlyOwner {
   198→        paused = true;
   199→        emit VaultPaused();
   200→    }
   201→
   202→    function unpause() external onlyOwner {
   203→        paused = false;
   204→        emit VaultUnpaused();
   205→    }
   206→
   207→    // ──────────────────────────────────────────────
   208→    //  Agent functions
   209→    // ──────────────────────────────────────────────
   210→
   211→    /// @notice Agent withdraws up to `yieldShareBps` percent of accrued yield.
   212→    ///         Subject to `withdrawalFrequency` cooldown between calls.
   213→    function agentWithdraw(uint256 wstETHAmount) external whenNotPaused nonReentrant {
   214→        if (msg.sender != agentWallet) revert NotAgent();
   215→        if (wstETHAmount == 0) revert ZeroAmount();
   216→        if (block.timestamp < uint256(lastAgentWithdrawal) + uint256(withdrawalFrequency)) {
   217→            revert CooldownNotElapsed();
   218→        }
   219→
   220→        uint256 yieldWstETH = getAccruedYieldInWstETH();
   221→        uint256 budget = yieldWstETH.mulDiv(yieldShareBps, BPS_DENOMINATOR);
   222→        if (wstETHAmount > budget) revert ExceedsBudget();
   223→
   224→        lastAgentWithdrawal = uint32(block.timestamp);
   225→
   226→        // principalStETH unchanged — agent only touches yield
   227→        IERC20(WSTETH).safeTransfer(agentWallet, wstETHAmount);
   228→
   229→        emit AgentWithdrawal(agentWallet, wstETHAmount);
   230→    }
   231→
   232→    // ──────────────────────────────────────────────
   233→    //  View functions
   234→    // ──────────────────────────────────────────────
   235→
   236→    /// @notice Returns accrued yield denominated in wstETH.
   237→    function getAccruedYieldInWstETH() public view returns (uint256) {
   238→        uint256 balance = IERC20(WSTETH).balanceOf(address(this));
   239→        if (balance == 0) return 0;
   240→
   241→        uint256 currentRate = _getCurrentRate();
   242→        uint256 totalValueStETH = balance.mulDiv(currentRate, 1e18);
   243→
   244→        if (totalValueStETH <= principalStETH) return 0;
   245→
   246→        uint256 yieldStETH = totalValueStETH - principalStETH;
   247→        return yieldStETH.mulDiv(1e18, currentRate);
   248→    }
   249→
   250→    /// @notice Returns the wstETH amount the agent can withdraw right now.
   251→    ///         Returns 0 if the cooldown has not elapsed.
   252→    function getAgentBudget() external view returns (uint256) {
   253→        if (block.timestamp < uint256(lastAgentWithdrawal) + uint256(withdrawalFrequency)) return 0;
   254→
   255→        uint256 yieldWstETH = getAccruedYieldInWstETH();
   256→        return yieldWstETH.mulDiv(yieldShareBps, BPS_DENOMINATOR);
   257→    }
   258→
   259→    /// @notice Total value held in the vault, denominated in stETH.
   260→    function getTotalValueInStETH() external view returns (uint256) {
   261→        uint256 balance = IERC20(WSTETH).balanceOf(address(this));
   262→        if (balance == 0) return 0;
   263→        uint256 currentRate = _getCurrentRate();
   264→        return balance.mulDiv(currentRate, 1e18);
   265→    }
   266→
   267→    /// @notice Current wstETH/stETH exchange rate from Chainlink (18 decimals).
   268→    function getCurrentRate() external view returns (uint256) {
   269→        return _getCurrentRate();
   270→    }
   271→
   272→    // ──────────────────────────────────────────────
   273→    //  Internal
   274→    // ──────────────────────────────────────────────
   275→
   276→    function _getCurrentRate() internal view returns (uint256) {
   277→        (, int256 answer,, uint256 updatedAt,) = IAggregatorV3(ORACLE).latestRoundData();
   278→        if (answer <= 0) revert InvalidOracleAnswer();
   279→        if (block.timestamp - updatedAt > ORACLE_STALENESS) revert StaleOracle();
   280→        return uint256(answer);
   281→    }
   282→}
   283→
   284→/// @dev Minimal interface the vault uses to check factory-level pause.
   285→interface IYieldVaultFactory {
   286→    function paused() external view returns (bool);
   287→}
   288→

