        return _agentVaults[agent];
    }

    // ──────────────────────────────────────────────
    //  Internal
    // ──────────────────────────────────────────────

    function _removeAgentVault(address agent, address vault) internal {
        address[] storage arr = _agentVaults[agent];
        uint256 len = arr.length;
        for (uint256 i = 0; i < len; i++) {
            if (arr[i] == vault) {
                arr[i] = arr[len - 1];
                arr.pop();
                return;
            }
        }
    }
