        _locked = 0;
    }

    // ──────────────────────────────────────────────
    //  Initialization (called once by factory)
    // ──────────────────────────────────────────────

    function initialize(
        address _factory,
        address _owner,
        address _agent,
        uint16 _yieldShareBps,
        uint32 _frequency
    ) external {
