        if (_yieldShareBps > BPS_DENOMINATOR) revert InvalidYieldShare();

        initialized = true;
        factory = _factory;
        owner = _owner;
        agentWallet = _agent;
        yieldShareBps = _yieldShareBps;
        withdrawalFrequency = _frequency;
    }

