    address constant WSTETH = 0xc1CBa3fCea344f92D9239c08C0568f6F2F0ee452;
    address constant ORACLE = 0xB88BAc61a4Ca37C43a3725912B1f472c9A5bc061;

    // ── Actors ──────────────────────────────────
    address admin    = makeAddr("admin");
