        uint256 newRate = initialRate * 105 / 100;
        _mockRate(newRate);

        uint256 yield_ = vault.getAccruedYieldInWstETH();
        uint256 balBefore = IERC20(WSTETH).balanceOf(user);
        uint256 principalBefore = vault.principalStETH();

